#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e6+6;

struct Edge{
    int to,val;
};

int n,hu,hv,hw,in_edge,fa[N],b[N],df[N];
int head[N],nxt[N<<1],tot;
Edge ver[N<<1];
ll f[N],p[N],ans,res;
bool h[N];

void add(int x,int y,int z){
	ver[++tot]={y,z},nxt[tot]=head[x],head[x]=tot;
}

void dfs1(int x,int fat,int fedge){
    b[x]=1,fa[x]=fat;
    ll lmx=0;
    Edge y=ver[head[x]];
    for(int i=head[x];i;i=nxt[i],y=ver[i])
        if(!b[y.to]){
            df[y.to]=y.val;
            dfs1(y.to,x,i);
            if(f[y.to]+y.val>f[x])
                lmx=f[x],f[x]=f[y.to]+y.val;
            else
                lmx=max(lmx,f[y.to]+y.val);
        }else if(i!=(fedge^1) && !hu)
            hu=x,hv=y.to,hw=y.val,in_edge=i;
    res=max(res,f[x]+lmx);
}

void dfs2(int x){
    f[x]=0,b[x]=2;
    Edge y=ver[head[x]];
    for(int i=head[x];i;i=nxt[i],y=ver[i])
        if(b[y.to]<2 && i!=in_edge && i!=(in_edge^1)){
            dfs2(y.to);
            if(!h[y.to])
                f[x]=max(f[x],f[y.to]+y.val);
        }
}

void solve(int st){
	res=hu=0;
    dfs1(st,0,0);
    ll sum=0,mx=0;
    for(int i=hu;i!=fa[hv];sum+=(i!=hv)*df[i],i=fa[i])
        h[i]=1,p[i]=sum;
    sum+=hw;
    dfs2(hv);
    for(int i=hu;i!=fa[hv];i=fa[i]){
        if(i!=hu)
            res=max(res,mx+f[i]+sum-p[i]);
        mx=max(mx,f[i]+p[i]);
    }
    ans+=res;
}

int main(){
    scanf("%d",&n);
    tot=1;
    for(int i=1,v,w;i<=n;i++){
        scanf("%d%d",&v,&w);
        add(i,v,w);
        add(v,i,w);
    }
    for(int i=1;i<=n;i++)
        if(!b[i])
            solve(i);
    printf("%lld",ans);
    return 0;
}
